---@class StructPet
local StructPet = LxClass("StructPet", nil)
---@class StructPetEquip
local StructPetEquip = LxClass("StructPetEquip",nil)

function StructPetEquip:StructPetEquip(refId)
    self._refId = refId --装备refId
    self._num = 0     --装备数量
    self._state = 0   --装备状态
    self._equipRef = gModelPet:GetPetEquipRef(self._refId)
    self._score = self._equipRef and self._equipRef.score or 0
    self._type = LItemTypeConst.TYPE_PET_EQUIP
end
function StructPetEquip:CreateByPb(pb)
    self._refId = pb.refId
    self._num = pb.num
    self._state = pb.state
    self._equipRef = self._equipRef or gModelPet:GetPetEquipRef(self._refId)
    self._score = self._equipRef and self._equipRef.score or 0
end
function StructPetEquip:GetRefId()
    return self._refId
end
function StructPetEquip:GetNum()
    return self._num
end
function StructPetEquip:GetScore()
    return self._score
end
function StructPetEquip:GetServerData()
    local data = {
        refId = self._refId,
        num = self._num,
        state = self._state,
        score = self._score,
        itype = self._type
    }
    return data
end
function StructPetEquip.NewStructPetEquip(refId)
    return StructPetEquip:New(refId)
end



function StructPet:StructPet(cfg)
    self._petRefId = cfg and cfg.refId --宠物refId
    self._star = 0      --星级
    self._level = 0     --等级
    ---@type table<StructPetEquip>
    self._petEquips = {}-- 宠物装扮
    self.petLinkHero = {}   --链接英雄-数组
    self.isActive = false---是否激活
    self.petCfg = cfg
    self.maxLevel = 0
    if cfg then
        local lvCfgs = gModelPet:GetLvConfig(cfg.quality)
        self.maxLevel = lvCfgs[#lvCfgs].lvNow
    end
end

function StructPet:CreateByPb(pb)
    self._petRefId = pb.petRefId
    self._star = pb.star
    self._level = pb.level
    self.isActive = true
    self:SetPetLink(pb.heroIds,self._petRefId)
    self._petEquips = {}
    for i ,v in ipairs(pb.equips or {}) do
        local equipCfg = GameTable.MagicPetArticleRef[v.refId]
        local equip = self._petEquips[equipCfg.type]
        if not equip then 
            equip = StructPetEquip:New()
            self._petEquips[equipCfg.type] = equip
        end
        equip:CreateByPb(v)
    end
    
end

function StructPet:SetPetLink(heroIds,petId)
    local heroList = self.petLinkHero or {}
    for _, hId in pairs(heroList) do
        if gModelPet.heroLinkPets[hId] then gModelPet.heroLinkPets[hId][petId] = nil end--清除旧连接数据
    end
    self.petLinkHero = {}--清除该宠物的链接
	for i ,hId in ipairs(heroIds or {}) do
        if not gModelPet.heroLinkPets[hId] then gModelPet.heroLinkPets[hId] = {} end
		self.petLinkHero[i] = hId
        gModelPet.heroLinkPets[hId][petId] = petId
	end
end


function StructPet:GetPetLinkHeroId(linkIndex)
    return self.petLinkHero[linkIndex]
end
---@return table<StructPetEquip>
function StructPet:GetPetWearEquips(isList)
    if isList then 
        local equipList = {}
        for _, equip in pairs(self._petEquips or {}) do
            table.insert(equipList,equip)
        end
        return equipList
    end
    return self._petEquips
end

function StructPet:RemoveLinkHeroById(heroId)
    for indx, value in ipairs(self.petLinkHero) do
        if value == heroId then 
            table.remove(self.petLinkHero,indx)
            return
        end
    end
end

function StructPet:GetPetState()--已激活1，可激活2，不可激活3
    if self.isActive then 
        return 1
    else
        local starCfg = self:GetPetStarCfg()
        return gModelPet:CheckCost(starCfg.upNeed) and 2 or 3
    end
end

function StructPet:IsCanUpStar(isTips)
    local starCfg = self:GetPetStarCfg()
    if starCfg and starCfg.rankNext<0 and self._star>0 then 
        if isTips then GF.ShowMessage(ccClientText(43760)) end
        return false
    end
    local nexStarCfg = self.isActive and GameTable.MagicPetStarRef[starCfg.rankNext] or starCfg
    return gModelPet:CheckCost(nexStarCfg.upNeed,isTips)
end
function StructPet:IsCanUpLevel(isTips)
    local lvCfg = self:GetLvCfg()
    if not lvCfg then return false end
	if lvCfg.lvNext<=0 and self._level>0 then
        if isTips then GF.ShowMessage(ccClientText(43717)) end
		return false
	end
    return gModelPet:CheckCost(lvCfg.upNeed,isTips)
end
--宠物是否能连接英雄（excludeHId已连接排除）
function StructPet:IsCanLinkHero(excludeHId)--
    if not self.isActive then return false end--未激活
    if gModelPet.heroLinkPets[excludeHId] and gModelPet.heroLinkPets[excludeHId][self._petRefId] then return false end --已連接
    local starCfgs = gModelPet.petStarCfg[self._petRefId]
	for _, value in pairs(starCfgs or {}) do
        if value.rankNow>self._star then return false end--槽位未開啟
		if value.link>0 and not self:GetPetLinkHeroId(value.link) then --未连接空位
            return true
        end
    end
end

function StructPet:IsCanEquip()
    if not self.isActive then return false end
    local equip = nil
    local partRef = GameTable.MagicPetArticleTypeRef
    for _, value in pairs(partRef) do
        equip =self._petEquips[value.refId]
        local isOk = false
        if equip then 
            isOk = gModelPet:GetStrongerEquipByPart(equip,value.refId)
        else
            isOk = gModelPet:GetWearRedPointByPart(value.refId)
        end
        if isOk then return isOk end
    end
    return false
end

function StructPet:GetMaxStar()
    local starCfgs = gModelPet.petStarCfg[self._petRefId]
    local cfg = starCfgs[#starCfgs]
    if cfg then return cfg.rankNow end
    return 0
end

function StructPet:GetPetConfig()
	return GameTable.MagicPetRef[self._petRefId]
end

function StructPet:GetPetStarCfg(star)
    return gModelPet.petStarCfg[self._petRefId][star or self._star]
end

function StructPet:GetLvCfg(level)
    return  gModelPet:GetLvConfig(self.petCfg.quality,level or self._level)
end

function StructPet:GetLvAttr(isStr)
    local lvCfg = self:GetLvCfg(math.max(self._level,1))
    if not lvCfg then return end
    return isStr and lvCfg.attr or LxDataHelper.ParseAttrList(lvCfg.attr)
end

function StructPet:GetStarAttr(isStr)
    local starCfg = self:GetPetStarCfg()
    if not self.isActive then return end
    return isStr and starCfg.attr or LxDataHelper.ParseAttrList(starCfg.attr)
end

function StructPet:GetLinkSkillDesc()
	local petStarCfg = self:GetPetStarCfg()
	local curSkillId = petStarCfg.skillId
	local skillStar = self._star
	while(curSkillId <=0 and petStarCfg.rankNext>0) do--當前星級沒技能-獲取下一級
		petStarCfg = GameTable.MagicPetStarRef[petStarCfg.rankNext]
		curSkillId = petStarCfg.skillId
		skillStar = petStarCfg.rankNow
	end
	local skillCfg = GameTable.SnakeSkillRef[curSkillId]
	if skillCfg then
		local desc = "<color=#d2730f>Lv."..petStarCfg.skillILv.."</color>："..ccLngText(skillCfg.description)
        local condition = string.replace(ccClientText(43713),skillStar)
        local isCondition = self._star~=skillStar or not self.isActive
		return desc,condition,isCondition
	end
end

function StructPet:GetAttrChangeAdd()
    if not self.isActive then return 0 end
    local starCfgs = gModelPet.petStarCfg[self._petRefId]
    local count = #starCfgs
    local petAttrAdd = 0
    for i = 0, count do
        local v = starCfgs[i]
        if self._star>= v.rankNow then 
            petAttrAdd = (v.attrChangeAdd and v.attrChangeAdd>0) and v.attrChangeAdd or petAttrAdd
        else
            break
        end
    end
    return petAttrAdd
end

function StructPet:GetEquipAttr(isStr)
    local str = ""
    local index = 0
    for _, equip in pairs(self._petEquips or {}) do
        index = index+1
        local cfg = GameTable.MagicPetArticleRef[equip._refId]
        if cfg and not string.isempty(cfg.attr) then str = str..cfg.attr.."," end
    end
    str = string.sub(str,1,#str-1)
    return isStr and str or LxDataHelper.ParseAttrList(str)
end

function StructPet:GetTotalAttrStr()
    local lvAttr = self:GetLvAttr(true)
	local starAttr = self:GetStarAttr(true)
    local equipAttr = self:GetEquipAttr(true)
	local attrStr = ""
    if not string.isempty(lvAttr) then attrStr = attrStr..","..lvAttr end
    if not string.isempty(starAttr) then attrStr = attrStr..","..starAttr end
    if not string.isempty(equipAttr) then attrStr = attrStr..","..equipAttr end
    attrStr = string.sub(attrStr,2,#attrStr)
    return attrStr
end

function StructPet:GetServerData()
    local data = {
        refId = self._petRefId,
        star = self._star,
        level = self._level,
        petEquips = self._petEquips ,
        petLinkHero = self.petLinkHero,
        isActive = self.isActive,
        petCfg = self.petCfg,
        maxLevel = self.maxLevel
    }
    return data
end

return StructPet